/**
 * role-list tool — list all roles defined in the guild.
 *
 * Returns all roles known to the system — both guild-defined and kit-contributed.
 *
 * See: docs/architecture/apparatus/loom.md
 */

import { tool } from '@shardworks/tools-apparatus';
import { guild } from '@shardworks/nexus-core';
import type { LoomApi } from '../loom.ts';

export default tool({
  name: 'role-list',
  description: 'List all roles defined in the guild',
  params: {},
  permission: 'read',
  handler: async () => {
    const loom = guild().apparatus<LoomApi>('loom');
    return loom.listRoles();
  },
});
