/**
 * role-show tool — show details of a specific role.
 *
 * Returns the role info for a named role. Throws if the role is not found.
 *
 * See: docs/architecture/apparatus/loom.md
 */

import { tool } from '@shardworks/tools-apparatus';
import { guild } from '@shardworks/nexus-core';
import { z } from 'zod';
import type { LoomApi } from '../loom.ts';

export default tool({
  name: 'role-show',
  description: 'Show details of a specific role',
  params: {
    name: z.string().describe('The role name to look up'),
  },
  permission: 'read',
  handler: async (params) => {
    const loom = guild().apparatus<LoomApi>('loom');
    const roles = loom.listRoles();
    const role = roles.find((r) => r.name === params.name);
    if (!role) {
      throw new Error(`Role "${params.name}" not found.`);
    }
    return role;
  },
});
