1	/**
2	 * Parlour — chat UI application logic.
3	 *
4	 * Vanilla JS, no build step. Communicates with the Parlour API routes
5	 * via fetch(). SSE from POST /api/parlour/turn is read by manually
6	 * parsing the ReadableStream (EventSource only supports GET).
7	 */
8	
9	// ── State ─────────────────────────────────────────────────────────────
10	
11	let currentRole = null;
12	let currentCodex = '';       // empty = guild home
13	let currentConversationId = null;
14	let isStreaming = false;
15	let currentAnimaMessageEl = null;  // the anima message bubble being streamed
16	
17	// Per-conversation cost aggregation (updated after each turn)
18	let turnCostData = [];  // [{ costUsd, inputTokens, outputTokens }, ...]
19	
20	// ── DOM references ────────────────────────────────────────────────────
21	
22	const roleSelect = document.getElementById('role-select');
23	const codexSelect = document.getElementById('codex-select');
24	const parlourMain = document.getElementById('parlour-main');
25	const newConvBtn = document.getElementById('new-conversation-btn');
26	const convListEl = document.getElementById('conversation-list');
27	const chatMessages = document.getElementById('chat-messages');
28	const chatInput = document.getElementById('chat-input');
29	const sendBtn = document.getElementById('send-btn');
30	const costCard = document.getElementById('cost-card');
31	const costDetails = document.getElementById('cost-details');
32	
33	// ── Initialisation ────────────────────────────────────────────────────
34	
35	async function init() {
36	  await Promise.all([loadRoles(), loadCodexes()]);
37	}
38	
39	async function loadRoles() {
40	  try {
41	    const res = await fetch('/api/parlour/roles');
42	    if (!res.ok) return;
43	    const roles = await res.json();
44	    roles.sort((a, b) => a.name.localeCompare(b.name));
45	    for (const role of roles) {
46	      const opt = document.createElement('option');
47	      opt.value = role.name;
48	      opt.textContent = role.name + (role.source === 'kit' ? ' (kit)' : '');
49	      roleSelect.appendChild(opt);
50	    }
51	  } catch {
52	    // Roles endpoint not available — silently omit
53	  }
54	}
55	
56	async function loadCodexes() {
57	  try {
58	    const res = await fetch('/api/codex/list');
59	    if (!res.ok) return;
60	    const codexes = await res.json();
61	    for (const codex of codexes) {
62	      const opt = document.createElement('option');
63	      opt.value = codex.name;
64	      opt.textContent = codex.name;
65	      codexSelect.appendChild(opt);
66	    }
67	  } catch {
68	    // Codexes not installed — silently omit
69	  }
70	}
71	
72	// ── Role / Codex selection ─────────────────────────────────────────────
73	
74	roleSelect.addEventListener('change', () => {
75	  const role = roleSelect.value;
76	  if (!role) return;
77	  onRoleChange(role);
78	});
79	
80	codexSelect.addEventListener('change', () => {
81	  currentCodex = codexSelect.value;
82	});
83	
84	function onRoleChange(role) {
85	  currentRole = role;
86	  currentConversationId = null;
87	  currentAnimaMessageEl = null;
88	  turnCostData = [];
89	  clearChat();
90	  parlourMain.classList.remove('hidden');
91	  costCard.classList.add('hidden');
92	  loadConversations(role);
93	}
94	
95	// ── Conversations sidebar ─────────────────────────────────────────────
96	
97	async function loadConversations(role) {
98	  try {
99	    const res = await fetch(`/api/parlour/conversations?role=${encodeURIComponent(role)}&status=active`);
100	    if (!res.ok) return;
101	    const convs = await res.json();
102	    renderConversationList(convs);
103	  } catch {
104	    // Silently ignore
105	  }
106	}
107	
108	function renderConversationList(convs) {
109	  convListEl.innerHTML = '';
110	  for (const conv of convs) {
111	    appendConversationItem(conv);
112	  }
113	}
114	
115	function appendConversationItem(conv) {
116	  const item = document.createElement('div');
117	  item.className = 'conversation-item';
118	  item.dataset.id = conv.id;
119	
120	  const titleEl = document.createElement('span');
121	  titleEl.className = 'conversation-item__title';
122	  titleEl.textContent = conv.title;
123	  titleEl.title = conv.title;
124	
125	  const endBtn = document.createElement('button');
126	  endBtn.className = 'end-btn';
127	  endBtn.textContent = 'End';
128	  endBtn.title = 'End this conversation';
129	  endBtn.addEventListener('click', (e) => {
130	    e.stopPropagation();
131	    onEndConversation(conv.id);
132	  });
133	
134	  item.appendChild(titleEl);
135	  item.appendChild(endBtn);
136	  item.addEventListener('click', () => onSelectConversation(conv.id));
137	
138	  if (conv.id === currentConversationId) {
139	    item.classList.add('conversation-item--active');
140	  }
141	
142	  convListEl.appendChild(item);
143	}
144	
145	function setActiveConversationInSidebar(id) {
146	  for (const item of convListEl.querySelectorAll('.conversation-item')) {
147	    if (item.dataset.id === id) {
148	      item.classList.add('conversation-item--active');
149	    } else {
150	      item.classList.remove('conversation-item--active');
151	    }
152	  }
153	}
154	
155	// ── New conversation ───────────────────────────────────────────────────
156	
157	newConvBtn.addEventListener('click', onNewConversation);
158	
159	function onNewConversation() {
160	  currentConversationId = null;
161	  currentAnimaMessageEl = null;
162	  turnCostData = [];
163	  clearChat();
164	  costCard.classList.add('hidden');
165	  setActiveConversationInSidebar(null);
166	  sendBtn.disabled = false;
167	  chatMessages.classList.remove('empty-state');
168	  chatMessages.textContent = '';
169	
170	  // Show placeholder
171	  const placeholder = document.createElement('div');
172	  placeholder.className = 'message message--system';
173	  placeholder.textContent = 'New conversation — type a message to begin';
174	  chatMessages.appendChild(placeholder);
175	}
176	
177	// ── End conversation ───────────────────────────────────────────────────
178	
179	async function onEndConversation(id) {
180	  try {
181	    await fetch('/api/conversation/end', {
182	      method: 'POST',
183	      headers: { 'Content-Type': 'application/json' },
184	      body: JSON.stringify({ id, reason: 'concluded' }),
185	    });
186	  } catch {
187	    // Ignore
188	  }
189	
190	  // Remove from sidebar
191	  const item = convListEl.querySelector(`[data-id="${id}"]`);
192	  if (item) item.remove();
193	
194	  // If current conversation ended, go to new conversation state
195	  if (currentConversationId === id) {
196	    onNewConversation();
197	  }
198	}
199	
200	// ── Select conversation ────────────────────────────────────────────────
201	
202	async function onSelectConversation(id) {
203	  currentConversationId = id;
204	  currentAnimaMessageEl = null;
205	  turnCostData = [];
206	  setActiveConversationInSidebar(id);
207	
208	  try {
209	    const res = await fetch(`/api/conversation/show?id=${encodeURIComponent(id)}`);
210	    if (!res.ok) {
211	      showSystemMessage('Failed to load conversation history');
212	      return;
213	    }
214	    const detail = await res.json();
215	    renderConversationHistory(detail);
216	    sendBtn.disabled = false;
217	  } catch {
218	    showSystemMessage('Failed to load conversation history');
219	  }
220	}
221	
222	function renderConversationHistory(detail) {
223	  clearChat();
224	  chatMessages.classList.remove('empty-state');
225	
226	  if (!detail.turns || detail.turns.length === 0) {
227	    const placeholder = document.createElement('div');
228	    placeholder.className = 'message message--system';
229	    placeholder.textContent = 'No messages yet';
230	    chatMessages.appendChild(placeholder);
231	  } else {
232	    for (const turn of detail.turns) {
233	      if (turn.sessionId === null) {
234	        // Human turn
235	        if (turn.message) {
236	          appendMessage({ role: 'human', author: 'User', text: turn.message });
237	        }
238	      } else {
239	        // Anima turn
240	        const text = turn.output || '[No response recorded]';
241	        appendMessage({
242	          role: 'anima',
243	          author: currentRole || 'Anima',
244	          text,
245	          dim: !turn.output,
246	        });
247	
248	        // Collect cost data
249	        if (turn.costUsd !== null || turn.tokenUsage !== null) {
250	          turnCostData.push({
251	            costUsd: turn.costUsd ?? 0,
252	            inputTokens: turn.tokenUsage?.inputTokens ?? 0,
253	            outputTokens: turn.tokenUsage?.outputTokens ?? 0,
254	          });
255	        }
256	      }
257	    }
258	  }
259	
260	  updateCostCard();
261	  scrollToBottom();
262	}
263	
264	// ── Chat rendering ────────────────────────────────────────────────────
265	
266	function clearChat() {
267	  chatMessages.innerHTML = '';
268	  chatMessages.className = 'empty-state';
269	}
270	
271	function appendMessage({ role, author, text, dim = false }) {
272	  const wrapper = document.createElement('div');
273	  wrapper.className = `message message--${role}`;
274	
275	  const authorEl = document.createElement('div');
276	  authorEl.className = 'message-author';
277	  authorEl.textContent = author;
278	
279	  const contentEl = document.createElement('div');
280	  contentEl.className = 'message-content';
281	  if (dim) contentEl.style.color = 'var(--text-dim, #787c99)';
282	  contentEl.textContent = text;
283	
284	  wrapper.appendChild(authorEl);
285	  wrapper.appendChild(contentEl);
286	  chatMessages.appendChild(wrapper);
287	  return wrapper;
288	}
289	
290	function showSystemMessage(text) {
291	  const el = document.createElement('div');
292	  el.className = 'message message--system';
293	  el.textContent = text;
294	  chatMessages.appendChild(el);
295	  scrollToBottom();
296	}
297	
298	function showTypingIndicator() {
299	  const indicator = document.createElement('div');
300	  indicator.className = 'typing-indicator';
301	  indicator.id = 'typing-indicator';
302	  indicator.innerHTML = '<span></span><span></span><span></span>';
303	  chatMessages.appendChild(indicator);
304	  scrollToBottom();
305	  return indicator;
306	}
307	
308	function removeTypingIndicator() {
309	  const indicator = document.getElementById('typing-indicator');
310	  if (indicator) indicator.remove();
311	}
312	
313	function scrollToBottom() {
314	  chatMessages.scrollTop = chatMessages.scrollHeight;
315	}
316	
317	// ── Cost card ─────────────────────────────────────────────────────────
318	
319	function updateCostCard() {
320	  if (turnCostData.length === 0) {
321	    costCard.classList.add('hidden');
322	    return;
323	  }
324	
325	  const totalCost = turnCostData.reduce((sum, t) => sum + (t.costUsd || 0), 0);
326	  const totalInput = turnCostData.reduce((sum, t) => sum + (t.inputTokens || 0), 0);
327	  const totalOutput = turnCostData.reduce((sum, t) => sum + (t.outputTokens || 0), 0);
328	
329	  costDetails.innerHTML = `
330	    <div>
331	      <span class="badge">IN: ${totalInput.toLocaleString()}</span>
332	      <span class="badge">OUT: ${totalOutput.toLocaleString()}</span>
333	    </div>
334	    <div class="cost-usd">$${totalCost.toFixed(4)}</div>
335	  `;
336	
337	  costCard.classList.remove('hidden');
338	}
339	
340	// ── Send message ──────────────────────────────────────────────────────
341	
342	sendBtn.addEventListener('click', sendMessage);
343	
344	chatInput.addEventListener('keydown', (e) => {
345	  if (e.ctrlKey && e.key === 'Enter') {
346	    e.preventDefault();
347	    sendMessage();
348	  }
349	});
350	
351	chatInput.addEventListener('input', () => {
352	  chatInput.style.height = 'auto';
353	  chatInput.style.height = Math.min(chatInput.scrollHeight, 200) + 'px';
354	});
355	
356	async function sendMessage() {
357	  if (isStreaming) return;
358	
359	  const text = chatInput.value.trim();
360	  if (!text) return;
361	
362	  isStreaming = true;
363	  sendBtn.disabled = true;
364	  chatInput.value = '';
365	  chatInput.style.height = 'auto';
366	
367	  // Remove empty-state class and content if present
368	  if (chatMessages.classList.contains('empty-state')) {
369	    chatMessages.classList.remove('empty-state');
370	    chatMessages.innerHTML = '';
371	  }
372	
373	  // Render human message
374	  appendMessage({ role: 'human', author: 'User', text });
375	
376	  // Show typing indicator
377	  showTypingIndicator();
378	
379	  // Start anima message bubble (will be filled progressively)
380	  currentAnimaMessageEl = null;
381	
382	  // Build request body
383	  const body = {
384	    message: text,
385	    role: currentRole,
386	    ...(currentConversationId ? { conversationId: currentConversationId } : {}),
387	    ...(currentCodex ? { codexName: currentCodex } : {}),
388	  };
389	
390	  try {
391	    const response = await fetch('/api/parlour/turn', {
392	      method: 'POST',
393	      headers: { 'Content-Type': 'application/json' },
394	      body: JSON.stringify(body),
395	    });
396	
397	    if (!response.ok || !response.body) {
398	      removeTypingIndicator();
399	      showSystemMessage(`Error: HTTP ${response.status}`);
400	      isStreaming = false;
401	      sendBtn.disabled = false;
402	      return;
403	    }
404	
405	    await readSSEStream(response.body);
406	  } catch (err) {
407	    removeTypingIndicator();
408	    showSystemMessage(`Error: ${err.message}`);
409	    isStreaming = false;
410	    sendBtn.disabled = false;
411	  }
412	}
413	
414	// ── SSE stream reader ─────────────────────────────────────────────────
415	
416	/**
417	 * Read an SSE stream from a POST response body.
418	 * EventSource only supports GET, so we parse SSE manually.
419	 */
420	async function readSSEStream(body) {
421	  const reader = body.getReader();
422	  const decoder = new TextDecoder();
423	  let buffer = '';
424	
425	  try {
426	    while (true) {
427	      const { value, done } = await reader.read();
428	      if (done) break;
429	      buffer += decoder.decode(value, { stream: true });
430	
431	      // Process complete SSE messages (terminated by double newline)
432	      const messages = buffer.split(/\n\n/);
433	      buffer = messages.pop() ?? ''; // last element may be incomplete
434	
435	      for (const message of messages) {
436	        processSSEMessage(message);
437	      }
438	    }
439	
440	    // Process any remaining buffer
441	    if (buffer.trim()) {
442	      processSSEMessage(buffer);
443	    }
444	  } finally {
445	    reader.releaseLock();
446	    // Ensure streaming state is cleaned up
447	    if (isStreaming) {
448	      removeTypingIndicator();
449	      isStreaming = false;
450	      sendBtn.disabled = false;
451	    }
452	  }
453	}
454	
455	function processSSEMessage(raw) {
456	  const lines = raw.split('\n');
457	  let event = 'message';
458	  let data = '';
459	
460	  for (const line of lines) {
461	    if (line.startsWith('event: ')) {
462	      event = line.slice('event: '.length).trim();
463	    } else if (line.startsWith('data: ')) {
464	      data = line.slice('data: '.length).trim();
465	    }
466	  }
467	
468	  if (!data) return;
469	
470	  let parsed;
471	  try {
472	    parsed = JSON.parse(data);
473	  } catch {
474	    return;
475	  }
476	
477	  handleSSEEvent(event, parsed);
478	}
479	
480	function handleSSEEvent(event, data) {
481	  switch (event) {
482	    case 'conversation_created':
483	      currentConversationId = data.conversationId;
484	      // Add new conversation to sidebar
485	      appendConversationItem({
486	        id: data.conversationId,
487	        title: 'New conversation…',
488	      });
489	      setActiveConversationInSidebar(data.conversationId);
490	      break;
491	
492	    case 'chunk':
493	      handleChunk(data);
494	      break;
495	
496	    case 'error':
497	      removeTypingIndicator();
498	      showSystemMessage(`Error: ${data.error || 'Unknown error'}`);
499	      isStreaming = false;
500	      sendBtn.disabled = false;
501	      break;
502	
503	    default:
504	      break;
505	  }
506	}
507	
508	function handleChunk(chunk) {
509	  switch (chunk.type) {
510	    case 'text': {
511	      // Remove typing indicator on first text chunk
512	      removeTypingIndicator();
513	
514	      if (!currentAnimaMessageEl) {
515	        // Create the anima message bubble
516	        const wrapper = document.createElement('div');
517	        wrapper.className = 'message message--anima';
518	
519	        const authorEl = document.createElement('div');
520	        authorEl.className = 'message-author';
521	        authorEl.textContent = currentRole || 'Anima';
522	
523	        const contentEl = document.createElement('div');
524	        contentEl.className = 'message-content';
525	
526	        wrapper.appendChild(authorEl);
527	        wrapper.appendChild(contentEl);
528	        chatMessages.appendChild(wrapper);
529	        currentAnimaMessageEl = contentEl;
530	      }
531	
532	      currentAnimaMessageEl.textContent += chunk.text;
533	      scrollToBottom();
534	      break;
535	    }
536	
537	    case 'tool_use': {
538	      removeTypingIndicator();
539	      if (!currentAnimaMessageEl) {
540	        // Create bubble if needed
541	        const wrapper = document.createElement('div');
542	        wrapper.className = 'message message--anima';
543	        const authorEl = document.createElement('div');
544	        authorEl.className = 'message-author';
545	        authorEl.textContent = currentRole || 'Anima';
546	        const contentEl = document.createElement('div');
547	        contentEl.className = 'message-content';
548	        wrapper.appendChild(authorEl);
549	        wrapper.appendChild(contentEl);
550	        chatMessages.appendChild(wrapper);
551	        currentAnimaMessageEl = contentEl;
552	      }
553	      const pill = document.createElement('span');
554	      pill.className = 'tool-indicator';
555	      pill.textContent = `⚙ ${chunk.name || 'tool'}`;
556	      currentAnimaMessageEl.appendChild(pill);
557	      scrollToBottom();
558	      break;
559	    }
560	
561	    case 'tool_result': {
562	      if (currentAnimaMessageEl) {
563	        const pill = document.createElement('span');
564	        pill.className = 'tool-indicator';
565	        pill.textContent = `✓ ${chunk.name || 'result'}`;
566	        currentAnimaMessageEl.appendChild(pill);
567	        scrollToBottom();
568	      }
569	      break;
570	    }
571	
572	    case 'turn_complete': {
573	      // Collect cost data for this turn
574	      if (chunk.costUsd !== undefined && chunk.costUsd !== null) {
575	        // We'll do a full refresh of cost after fetching conversation detail
576	        // For now, add a placeholder entry that will be replaced
577	        turnCostData.push({
578	          costUsd: chunk.costUsd,
579	          inputTokens: 0,
580	          outputTokens: 0,
581	        });
582	      }
583	
584	      currentAnimaMessageEl = null;
585	      isStreaming = false;
586	      sendBtn.disabled = false;
587	
588	      // Refresh conversation detail for full token data
589	      if (currentConversationId) {
590	        refreshConversationCost(currentConversationId);
591	      }
592	      break;
593	    }
594	
595	    default:
596	      break;
597	  }
598	}
599	
600	/**
601	 * Re-fetch conversation detail to get accurate token totals and refresh the cost card.
602	 */
603	async function refreshConversationCost(id) {
604	  try {
605	    const res = await fetch(`/api/conversation/show?id=${encodeURIComponent(id)}`);
606	    if (!res.ok) return;
607	    const detail = await res.json();
608	
609	    // Rebuild cost data from full turn history
610	    turnCostData = [];
611	    for (const turn of detail.turns) {
612	      if (turn.sessionId !== null && (turn.costUsd !== null || turn.tokenUsage !== null)) {
613	        turnCostData.push({
614	          costUsd: turn.costUsd ?? 0,
615	          inputTokens: turn.tokenUsage?.inputTokens ?? 0,
616	          outputTokens: turn.tokenUsage?.outputTokens ?? 0,
617	        });
618	      }
619	    }
620	
621	    updateCostCard();
622	
623	    // Also update sidebar title if this was a new conversation
624	    refreshConversationTitle(id);
625	  } catch {
626	    // Ignore
627	  }
628	}
629	
630	async function refreshConversationTitle(id) {
631	  try {
632	    const role = encodeURIComponent(currentRole || '');
633	    const res = await fetch(`/api/parlour/conversations?role=${role}&status=active`);
634	    if (!res.ok) return;
635	    const convs = await res.json();
636	    const conv = convs.find((c) => c.id === id);
637	    if (!conv) return;
638	
639	    const item = convListEl.querySelector(`[data-id="${id}"]`);
640	    if (item) {
641	      const titleEl = item.querySelector('.conversation-item__title');
642	      if (titleEl) {
643	        titleEl.textContent = conv.title;
644	        titleEl.title = conv.title;
645	      }
646	    }
647	  } catch {
648	    // Ignore
649	  }
650	}
651	
652	// ── Bootstrap ─────────────────────────────────────────────────────────
653	
654	init();
