      const requestPath = c.req.path;
      const prefix = `/pages/${page.id}/`;
      const filePath = requestPath.slice(prefix.length) || 'index.html';

      // Prevent directory traversal
      if (filePath.includes('..')) {
        return c.text('Not found', 404);
      }

