  pluginId: string;
  packageName: string;
  value: T;
}

interface ContributionRegistry {
  /** Get all contributions for a given supportKit key. */
  get<T>(key: string): ContributionEntry<T>[];
}
```

During the Wire phase, Arbor collects:

```typescript
