  const kit = 'kit' in plugin ? plugin.kit : plugin.apparatus.supportKit;
  if (!kit || typeof kit !== 'object') continue;

  for (const [key, value] of Object.entries(kit)) {
    // Skip 'books' — already handled specially by Stacks
    registry.add(key, plugin.id, plugin.packageName, value);
  }
